/**
 * FINIFY AI: INSTITUTIONAL THEME TOKENS
 * Optimized for high-fidelity stock portfolio generation.
 */

export const theme = {
  colors: {
    background: '#0a0a0a',        // Deep Charcoal Base
    surface: '#141414',           // Elevated Card Surface
    emerald: '#10b981',           // Primary Branding
    emeraldGlow: 'rgba(16, 185, 129, 0.2)',
    border: 'rgba(255, 255, 255, 0.08)',
    text: {
      primary: '#ffffff',
      secondary: 'rgba(255, 255, 255, 0.4)',
      accent: '#10b981'
    }
  },
  
  shadows: {
    premium: '0 20px 40px rgba(0, 0, 0, 0.6)',
    glow: '0 0 20px rgba(16, 185, 129, 0.1)'
  },

  transitions: {
    standard: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
    slow: 'all 0.7s ease-in-out'
  }
};
